DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "PGchoicemacros.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Fraction");
do {$r = Fraction(non_zero_random(-9,9,1),random(2,9,1))} until (($r->value)[1] != 1);
$s = non_zero_random(-9,9,1);
($r,$s) = num_sort($r,$s);
$B = -($r + $s);
$C = $r*$s;
$a = lcm(($B->value)[1],($C->value)[1]);
$b = $a*$B;
$c = $a*$C;
Context()->noreduce('(-x)-y','(-x)+y');
$f = Formula("$a x^2 + $b x + $c")->reduce;
($left,$right) = (Formula("-$b x"),Formula("-$c"))[NchooseK(2,2)];
$left = Formula("$a x^2-$left")->reduce;
$right = $right->reduce;
$negb = -$b;
$bsquared = ($b)**2;
$discriminant = ($b)**2 - 4*$a*$c;
$sqrtdisc = Fraction(sqrt($discriminant));
$a2 = 2*$a;
Context("FiniteSolutionSets");
$solutions = Formula("{$r,$s}");

############################################################
# Body
############################################################

BEGIN_PGML
Use the quadratic formula to solve the equation.

[`[$left]=[$right]`]

[@KeyboardInstructions('If you need to enter a square root like [`\sqrt{17}\text{,}`] type [|sqrt(17)|]*. If there is no real solution, enter [|no real solution|]*.')@]**

[_]{$solutions}{40}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
To use the quadratic formula, we write the equation in standard form:

[```[$f]=0```]

and identify [`a=[$a]\text{,}`] [`b=[$b]\text{,}`] and [`c=[$c]\text{.}`]

[```\newcommand{\amp}{&}
\begin{aligned}
x\amp=\frac{-b\pm\sqrt{b^2-4ac}}{2a}\\
\amp=\frac{[$negb]\pm\sqrt{[$bsquared]-4([$a])([$c])}}{2([$a])}\\
\amp=\frac{[$negb]\pm\sqrt{[$discriminant]}}{[$a2]}\\
\amp=\frac{[$negb]\pm[$sqrtdisc]}{[$a2]}\\
x\amp=\frac{[$negb]-[$sqrtdisc]}{[$a2]}\quad\text{or}\quad x=\frac{[$negb]+[$sqrtdisc]}{[$a2]}\\
x\amp=[$r]\quad\text{or}\quad x=[$s]
\end{aligned}
```]

The solution set is [`[$solutions]\text{.}`]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
